  1	import * as React from 'react';
  2	import { Workload } from 'types/Workload';
  3	import { Pod, ZtunnelConfigDump } from 'types/IstioObjects';
  4	import * as API from '../../services/Api';
  5	import * as AlertUtils from '../../utils/AlertUtils';
  6	import { Card, CardBody, Tab, Tabs, TooltipPosition } from '@patternfly/react-core';
  7	import { activeTab } from '../../components/Tab/Tabs';
  8	import { location, router } from '../../app/History';
  9	import {
 10	  tabName as workloadTabName,
 11	  defaultTab as workloadDefaultTab
 12	} from '../../pages/WorkloadDetails/WorkloadDetailsPage';
 13	import { TimeInMilliseconds, TimeRange } from '../../types/Common';
 14	import { subTabStyle } from 'styles/TabStyles';
 15	import { ToolbarDropdown } from '../Dropdown/ToolbarDropdown';
 16	import { PFBadge, PFBadges } from '../Pf/PfBadges';
 17	import { kialiStyle } from '../../styles/StyleUtils';
 18	import { ZtunnelServicesTable } from './ZtunnelServicesTable';
 19	import { ZtunnelWorkloadsTable } from './ZtunnelWorkloadsTable';
 20	import { t } from 'i18next';
 21	import { SortableTh } from '../Table/SimpleTable';
 22	import { ZtunnelMetrics } from './ZtunnelMetrics';
 23	import { RenderComponentScroll } from 'components/Nav/Page';
 24	import { FilterSelected, StatefulFilters } from '../Filters/StatefulFilters';
 25	import { servicesFilters, workloadsFilters } from './Filters/ZtunnelFilters';
 26	import { ActiveFiltersInfo } from '../../types/Filters';
 27	import { runFilters } from '../FilterList/FilterHelper';
 28	import { ConfigType, ZtunnelLabels } from './Filters/ZtunnelLabels';
 29	
 30	const resources: string[] = ['services', 'workloads', 'metrics'];
 31	
 32	const ztunnelTabs = ['services', 'workloads', 'metrics'];
 33	const tabName = 'ztunnelTab';
 34	const defaultTab = 'services';
 35	
 36	type ZtunnelConfigProps = {
 37	  lastRefreshAt: TimeInMilliseconds;
 38	  namespace: string;
 39	  rangeDuration: TimeRange;
 40	  workload: Workload;
 41	};
 42	
 43	const iconStyle = kialiStyle({
 44	  display: 'inline-block',
 45	  alignSelf: 'center'
 46	});
 47	
 48	const toolbarStyle = kialiStyle({
 49	  marginBottom: '1.25rem',
 50	  display: 'flex',
 51	  alignItems: 'center'
 52	});
 53	
 54	const toolbarClass = kialiStyle({
 55	  display: 'flex',
 56	  paddingTop: '0'
 57	});
 58	
 59	export interface SortableCompareTh<T> extends SortableTh {
 60	  compare?: (a: T, b: T) => number;
 61	}
 62	
 63	export const yoverflow = kialiStyle({
 64	  height: 'calc(100vh - 400px)',
 65	  overflow: 'auto'
 66	});
 67	
 68	export const stickyThead: React.CSSProperties = {
 69	  position: 'sticky',
 70	  top: 0,
 71	  backgroundColor: 'white',
 72	  zIndex: 1
 73	};
 74	
 75	export const ZtunnelConfig: React.FC<ZtunnelConfigProps> = (props: ZtunnelConfigProps) => {
 76	  const sortedPods = (): Pod[] => {
 77	    return props.workload?.pods.sort((p1: Pod, p2: Pod) => (p1.name >= p2.name ? 1 : -1));
 78	  };
 79	
 80	  const [pod, setPod] = React.useState(sortedPods()[0]);
 81	  const [config, setConfig] = React.useState<ZtunnelConfigDump>({});
 82	  const [fetch, setFetch] = React.useState(true);
 83	  const [activeKey, setActiveKey] = React.useState(ztunnelTabs.indexOf(activeTab(tabName, defaultTab)));
 84	  const [resource, setResource] = React.useState(activeTab(tabName, defaultTab));
 85	  const [tabHeight, setTabHeight] = React.useState<number>(700);
 86	  const serviceFilters = servicesFilters(config);
 87	  const workloadFilters = workloadsFilters(config);
 88	
 89	  const [activeServiceFilters, setActiveServiceFilters] = React.useState<ActiveFiltersInfo>(
 90	    FilterSelected.init(serviceFilters)
 91	  );
 92	  const filteredServices = runFilters(config.services ? config.services : [], serviceFilters, activeServiceFilters);
 93	
 94	  const [activeWorkloadFilters, setActiveWorkloadFilters] = React.useState<ActiveFiltersInfo>(
 95	    FilterSelected.init(workloadFilters)
 96	  );
 97	  const filteredWorkloads = runFilters(
 98	    config.workloads ? config.workloads : [],
 99	    workloadFilters,
100	    activeWorkloadFilters
101	  );
102	
103	  const prevResource = React.createRef();
104	  const prevPod = React.createRef();
105	
106	  const fetchZtunnelConfig = React.useCallback(async (ns, name, cluster: string) => {
107	    await API.getPodZtunnelConfig(ns, name, cluster)
108	      .then(resultConfig => {
109	        setConfig(resultConfig.data);
110	        setFetch(false);
111	      })
112	      .catch(error => {
113	        AlertUtils.addError(`Could not fetch ztunnel config for ${name}.`, error);
114	      });
115	  }, []);
116	
117	  React.useEffect(() => {
118	    const currentTabIndex = ztunnelTabs.indexOf(activeTab(tabName, defaultTab));
119	    if (
120	      prevPod.current !== undefined &&
121	      prevPod.current !== pod &&
122	      prevResource.current !== undefined &&
123	      prevResource.current !== resource &&
124	      fetch === true
125	    ) {
126	      setFetch(false);
127	      fetchZtunnelConfig(props.namespace, pod.name, props.workload.cluster ? props.workload.cluster : '');
128	      if (currentTabIndex !== activeKey) {
129	        setActiveKey(currentTabIndex);
130	      }
131	    }
132	  }, [
133	    resource,
134	    pod,
135	    activeKey,
136	    prevPod,
137	    prevResource,
138	    fetchZtunnelConfig,
139	    fetch,
140	    props.namespace,
141	    props.workload.cluster
142	  ]);
143	
144	  const ztunnelHandleTabClick = (_event: React.MouseEvent, tabIndex: string | number): void => {
145	    const resourceIdx: number = +tabIndex;
146	    const targetResource: string = resources[resourceIdx];
147	
148	    if (targetResource !== resource) {
149	      setConfig({});
150	      setFetch(true);
151	      setResource(targetResource);
152	      setActiveKey(resourceIdx);
153	
154	      const mainTab = new URLSearchParams(location.getSearch()).get(workloadTabName) ?? workloadDefaultTab;
155	      const urlParams = new URLSearchParams(location.getSearch());
156	      urlParams.set(tabName, targetResource);
157	      urlParams.set(workloadTabName, mainTab);
158	      router.navigate(`${location.getPathname()}?${urlParams.toString()}`);
159	    }
160	  };
161	
162	  const setPodByKey = (podName: string): void => {
163	    const podIdx: number = +podName;
164	    const targetPod: Pod = sortedPods()[podIdx];
165	
166	    if (targetPod.name !== pod.name) {
167	      setConfig({});
168	      setPod(targetPod);
169	      setFetch(true);
170	    }
171	  };
172	
173	  const tabs: JSX.Element[] = [];
174	
175	  const servicesTab = (
176	    <Tab title={t('Services')} eventKey={0} key="services">
177	      <Card>
178	        <CardBody>
179	          <div>
180	            <div className={toolbarStyle}>
181	              <div key="service-icon" className={iconStyle}>
182	                <PFBadge badge={PFBadges.Pod} position={TooltipPosition.top} />
183	              </div>
184	              <ToolbarDropdown
185	                id="ztunnel_pods_list"
186	                tooltip={t('Display ztunnel config for the selected pod')}
187	                handleSelect={key => setPodByKey(key)}
188	                value={pod.name}
189	                label={pod.name}
190	                options={props.workload.pods.map((pod: Pod) => pod.name).sort()}
191	              />
192	              <div style={{ marginLeft: '1.25rem', marginRight: '0.5em' }}>{t('Filter')}:</div>
193	              <StatefulFilters
194	                initialFilters={serviceFilters}
195	                onFilterChange={active => setActiveServiceFilters(active)}
196	                toolbarClass={toolbarClass}
197	                cleanState
198	              >
199	                <ZtunnelLabels
200	                  key="service-labels"
201	                  filteredConfig={activeServiceFilters.filters.length > 0 ? filteredServices : config.services}
202	                  total={config?.services?.length ?? filteredServices.length}
203	                  type={ConfigType.SERVICE}
204	                />
205	              </StatefulFilters>
206	            </div>
207	            <ZtunnelServicesTable config={filteredServices} />
208	          </div>
209	        </CardBody>
210	      </Card>
211	    </Tab>
212	  );
213	  tabs.push(servicesTab);
214	
215	  const workloadsTab = (
216	    <Tab title={t('Workloads')} eventKey={1} key="workloads">
217	      <Card>
218	        <CardBody>
219	          <div>
220	            <div className={toolbarStyle}>
221	              <div key="service-icon" className={iconStyle}>
222	                <PFBadge badge={PFBadges.Pod} position={TooltipPosition.top} />
223	              </div>
224	              <ToolbarDropdown
225	                id="envoy_pods_list"
226	                tooltip={t('Display envoy config for the selected pod')}
227	                handleSelect={key => setPodByKey(key)}
228	                value={pod.name}
229	                label={pod.name}
230	                options={props.workload.pods.map((pod: Pod) => pod.name).sort()}
231	              />
232	              <div style={{ marginLeft: '1.25rem', marginRight: '0.5em' }}>{t('Filter')}:</div>
233	              <StatefulFilters
234	                initialFilters={workloadFilters}
235	                onFilterChange={active => setActiveWorkloadFilters(active)}
236	                toolbarClass={toolbarClass}
237	                cleanState
238	              >
239	                <ZtunnelLabels
240	                  key="workload-labels"
241	                  filteredConfig={activeWorkloadFilters.filters.length > 0 ? filteredWorkloads : config?.workloads}
242	                  total={config?.workloads?.length ?? filteredWorkloads.length}
243	                  type={ConfigType.WORKLOAD}
244	                />
245	              </StatefulFilters>
246	            </div>
247	            <ZtunnelWorkloadsTable config={filteredWorkloads} />
248	          </div>
249	        </CardBody>
250	      </Card>
251	    </Tab>
252	  );
253	  tabs.push(workloadsTab);
254	
255	  const metricsTab = (
256	    <Tab title={t('Metrics')} eventKey={2} key="metrics">
257	      <Card>
258	        <CardBody>
259	          <ZtunnelMetrics
260	            rangeDuration={props.rangeDuration}
261	            lastRefreshAt={props.lastRefreshAt}
262	            namespace={props.namespace}
263	            cluster={props.workload.cluster ? props.workload.cluster : ''}
264	            dashboardHeight={tabHeight - 200}
265	          />
266	        </CardBody>
267	      </Card>
268	    </Tab>
269	  );
270	  tabs.push(metricsTab);
271	
272	  return (
273	    <RenderComponentScroll onResize={height => setTabHeight(height)}>
274	      <Tabs
275	        id="ztunnel-details"
276	        className={subTabStyle}
277	        activeKey={activeKey}
278	        onSelect={ztunnelHandleTabClick}
279	        mountOnEnter={true}
280	        unmountOnExit={true}
281	      >
282	        {tabs}
283	      </Tabs>
284	    </RenderComponentScroll>
285	  );
286	};

